#!/usr/bin/env node
/**
 * Patches android/app/build.gradle (generated by `expo prebuild`) so the
 * release buildType uses a real PKCS12 release keystore instead of the
 * default Expo / React Native debug signing.
 *
 * Credentials are read from environment variables (provided by GitHub
 * Secrets in CI — never committed to the repository):
 *   ANDROID_KEYSTORE_PATH      absolute path to the decoded .p12 keystore
 *   ANDROID_KEYSTORE_PASSWORD  keystore password
 *   ANDROID_KEY_ALIAS          key alias
 *   ANDROID_KEY_PASSWORD       key password (same as keystore password)
 */
const fs = require('fs');
const path = require('path');

const gradlePath = path.join(__dirname, '..', 'android', 'app', 'build.gradle');

if (!fs.existsSync(gradlePath)) {
  console.error(`Cannot find ${gradlePath}. Run "npx expo prebuild --platform android" first.`);
  process.exit(1);
}

let gradle = fs.readFileSync(gradlePath, 'utf8');

if (gradle.includes('signingConfigs.release')) {
  console.log('Release signing already configured. Nothing to do.');
  process.exit(0);
}

const releaseSigningConfig = `
        release {
            storeFile file(System.getenv("ANDROID_KEYSTORE_PATH") ?: "release.p12")
            storePassword System.getenv("ANDROID_KEYSTORE_PASSWORD")
            keyAlias System.getenv("ANDROID_KEY_ALIAS")
            keyPassword System.getenv("ANDROID_KEY_PASSWORD")
            storeType "PKCS12"
        }`;

// 1. Add the release entry to the existing signingConfigs block.
if (!/signingConfigs\s*\{/.test(gradle)) {
  console.error('Could not find a signingConfigs block in build.gradle.');
  process.exit(1);
}
gradle = gradle.replace(/signingConfigs\s*\{/, (match) => `${match}${releaseSigningConfig}`);

// 2. Point the release buildType at signingConfigs.release, explicitly
//    overriding the default debug signing.
const releaseBlockRegex = /(buildTypes\s*\{[\s\S]*?release\s*\{[\s\S]*?)signingConfig\s+signingConfigs\.debug/;
if (!releaseBlockRegex.test(gradle)) {
  console.error('Could not find "signingConfig signingConfigs.debug" in the release buildType.');
  process.exit(1);
}
gradle = gradle.replace(releaseBlockRegex, '$1signingConfig signingConfigs.release');

fs.writeFileSync(gradlePath, gradle);
console.log('Release signing configured: release buildType now uses signingConfigs.release.');
